-- Seed Open Research content. Run once in the Supabase SQL Editor. Idempotent (upsert by slug).

alter table public.reports  add column if not exists position int;
alter table public.insights add column if not exists position int;

on conflict (slug) do update set category=excluded.category, title=excluded.title, summary=excluded.summary, key_points=excluded.key_points, body=excluded.body, sources=excluded.sources, source=excluded.source, date=excluded.date, live=excluded.live, position=excluded.position, updated_at=now();

on conflict (slug) do update set category=excluded.category, title=excluded.title, summary=excluded.summary, key_points=excluded.key_points, body=excluded.body, sources=excluded.sources, source=excluded.source, date=excluded.date, position=excluded.position, updated_at=now();
